void SS_igd_pc_init_function(	PC_ref 	*SS_pc_xeos,
							    int 	 iss,
							    char 	*name				){	
						 
	if (strcmp( name, "cpx") == 0){
		SS_pc_xeos[iss].ss_pc_xeos  = igd_cpx_pc_xeos; 		}
	else if (strcmp( name, "g")   == 0){
		SS_pc_xeos[iss].ss_pc_xeos  = igd_g_pc_xeos; 	    }
	else if (strcmp( name, "ilm") == 0){
		SS_pc_xeos[iss].ss_pc_xeos  = igd_ilm_pc_xeos; 		}
	else if (strcmp( name, "liq") == 0){
		SS_pc_xeos[iss].ss_pc_xeos  = igd_liq_pc_xeos; 		}
	else if (strcmp( name, "ol")  == 0){
		SS_pc_xeos[iss].ss_pc_xeos  = igd_ol_pc_xeos; 	    }
	else if (strcmp( name, "opx") == 0){
		SS_pc_xeos[iss].ss_pc_xeos  = igd_opx_pc_xeos; 		}
	else if (strcmp( name, "fsp") == 0){
		SS_pc_xeos[iss].ss_pc_xeos  = igd_fsp_pc_xeos; 	    }
	else if (strcmp( name, "spl") == 0){
		SS_pc_xeos[iss].ss_pc_xeos  = igd_spl_pc_xeos; 		}
	else{
		printf("\nsolid solution '%s' is not in the database, cannot be initiated [igd]\n", name);	
	}	
}
